         <span class="token comment">/* \u8FD9\u91CC\u591A\u4E2A\u51FD\u6570\u7B80\u5316\u4E86\uFF0C\u5982\u679C\u662F\u5408\u6210\u4E8B\u4EF6\uFF0C \u4F20\u5165\u6210\u4E8B\u4EF6\u540D\u79F0 onClick \uFF0C\u5411document\u6CE8\u518C\u4E8B\u4EF6  */</span>
